import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/java-tutor/design-pattern/prototype.html","title":"原型模式 (Prototype)","lang":"zh-CN","frontmatter":{"description":"原型模式 (Prototype) 通过复制已有对象来创建新对象，而不是通过 new 创建。 当对象的创建成本较高时，原型模式可以通过克隆来提升性能。 场景 对象创建成本高（数据库查询、网络请求、复杂计算） 对象的状态差异不大，只需要修改个别字段 Java 中实现 Cloneable 接口的场景 核心角色 代码示例 浅拷贝 vs 深拷贝 优缺点 JDK ...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"原型模式 (Prototype)\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-03T01:01:21.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/java-tutor/design-pattern/prototype.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"原型模式 (Prototype)"}],["meta",{"property":"og:description","content":"原型模式 (Prototype) 通过复制已有对象来创建新对象，而不是通过 new 创建。 当对象的创建成本较高时，原型模式可以通过克隆来提升性能。 场景 对象创建成本高（数据库查询、网络请求、复杂计算） 对象的状态差异不大，只需要修改个别字段 Java 中实现 Cloneable 接口的场景 核心角色 代码示例 浅拷贝 vs 深拷贝 优缺点 JDK ..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-03T01:01:21.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-03T01:01:21.000Z"}]]},"git":{"createdTime":1783040481000,"updatedTime":1783040481000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":1.51,"words":454},"filePathRelative":"java-tutor/design-pattern/prototype.md","autoDesc":true}`),a={name:`prototype.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="原型模式-prototype" tabindex="-1"><a class="header-anchor" href="#原型模式-prototype"><span>原型模式 (Prototype)</span></a></h1><blockquote><p><strong>通过复制已有对象来创建新对象，而不是通过 new 创建。</strong> 当对象的创建成本较高时，原型模式可以通过克隆来提升性能。</p></blockquote><h2 id="场景" tabindex="-1"><a class="header-anchor" href="#场景"><span>场景</span></a></h2><ul><li>对象创建成本高（数据库查询、网络请求、复杂计算）</li><li>对象的状态差异不大，只需要修改个别字段</li><li>Java 中实现 <code>Cloneable</code> 接口的场景</li></ul><h2 id="核心角色" tabindex="-1"><a class="header-anchor" href="#核心角色"><span>核心角色</span></a></h2><table><thead><tr><th>角色</th><th>说明</th></tr></thead><tbody><tr><td><strong>Prototype（原型）</strong></td><td>声明克隆方法的接口</td></tr><tr><td><strong>ConcretePrototype（具体原型）</strong></td><td>实现克隆方法</td></tr><tr><td><strong>Client（客户端）</strong></td><td>通过调用原型对象的 clone 来创建新对象</td></tr></tbody></table><h2 id="代码示例" tabindex="-1"><a class="header-anchor" href="#代码示例"><span>代码示例</span></a></h2><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">// 原型接口</span></span>
<span class="line"><span class="token keyword">interface</span> <span class="token class-name">Prototype</span> <span class="token keyword">extends</span> <span class="token class-name">Cloneable</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">Prototype</span> <span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 具体原型</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Shape</span> <span class="token keyword">implements</span> <span class="token class-name">Prototype</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">String</span> type<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">String</span> color<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">int</span> x<span class="token punctuation">,</span> y<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">Shape</span><span class="token punctuation">(</span><span class="token class-name">String</span> type<span class="token punctuation">,</span> <span class="token class-name">String</span> color<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>type <span class="token operator">=</span> type<span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>color <span class="token operator">=</span> color<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Getters and Setters</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setX</span><span class="token punctuation">(</span><span class="token keyword">int</span> x<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token keyword">this</span><span class="token punctuation">.</span>x <span class="token operator">=</span> x<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setY</span><span class="token punctuation">(</span><span class="token keyword">int</span> y<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token keyword">this</span><span class="token punctuation">.</span>y <span class="token operator">=</span> y<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token annotation punctuation">@Override</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">Prototype</span> <span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">Shape</span> clone <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Shape</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>type<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">.</span>color<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        clone<span class="token punctuation">.</span>x <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>x<span class="token punctuation">;</span></span>
<span class="line">        clone<span class="token punctuation">.</span>y <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>y<span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">return</span> clone<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token annotation punctuation">@Override</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string">&quot;Shape{type=&#39;&quot;</span> <span class="token operator">+</span> type <span class="token operator">+</span> <span class="token string">&quot;&#39;, color=&#39;&quot;</span> <span class="token operator">+</span> color <span class="token operator">+</span> <span class="token string">&quot;&#39;, x=&quot;</span> <span class="token operator">+</span> x <span class="token operator">+</span> <span class="token string">&quot;, y=&quot;</span> <span class="token operator">+</span> y <span class="token operator">+</span> <span class="token string">&quot;}&quot;</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ----- 使用 -----</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">PrototypeDemo</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// 创建一个原型（成本高，假设需要从数据库加载）</span></span>
<span class="line">        <span class="token class-name">Shape</span> circlePrototype <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Shape</span><span class="token punctuation">(</span><span class="token string">&quot;圆形&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;红色&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment">// 通过克隆创建新对象（成本低）</span></span>
<span class="line">        <span class="token class-name">Shape</span> circle1 <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">Shape</span><span class="token punctuation">)</span> circlePrototype<span class="token punctuation">.</span><span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        circle1<span class="token punctuation">.</span><span class="token function">setX</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        circle1<span class="token punctuation">.</span><span class="token function">setY</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">Shape</span> circle2 <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">Shape</span><span class="token punctuation">)</span> circlePrototype<span class="token punctuation">.</span><span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        circle2<span class="token punctuation">.</span><span class="token function">setX</span><span class="token punctuation">(</span><span class="token number">30</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        circle2<span class="token punctuation">.</span><span class="token function">setY</span><span class="token punctuation">(</span><span class="token number">40</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>circle1<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>circle2<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="浅拷贝-vs-深拷贝" tabindex="-1"><a class="header-anchor" href="#浅拷贝-vs-深拷贝"><span>浅拷贝 vs 深拷贝</span></a></h2><table><thead><tr><th>类型</th><th>说明</th><th>Java 实现</th></tr></thead><tbody><tr><td><strong>浅拷贝</strong></td><td>只复制基本类型和引用地址</td><td><code>Object.clone()</code> 默认</td></tr><tr><td><strong>深拷贝</strong></td><td>复制所有字段，包括引用的对象</td><td>重写 clone() 或序列化</td></tr></tbody></table><h2 id="优缺点" tabindex="-1"><a class="header-anchor" href="#优缺点"><span>优缺点</span></a></h2><table><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>✅ 提高创建性能（避免昂贵的初始化）</td><td>❌ 需要实现 Cloneable</td></tr><tr><td>✅ 简化创建过程</td><td>❌ 深拷贝实现复杂（循环引用问题）</td></tr><tr><td>✅ 可以动态增加产品类</td><td></td></tr></tbody></table><h2 id="jdk-中的应用" tabindex="-1"><a class="header-anchor" href="#jdk-中的应用"><span>JDK 中的应用</span></a></h2><ul><li><code>java.lang.Object.clone()</code>（需要实现 Cloneable）</li><li><code>java.util.Arrays.copyOf()</code></li><li>Spring 中的 Prototype Scope Bean（每次返回新实例）</li></ul>`,14)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};